import{V as t}from"./chunks/theme.DZcTFywn.js";import{c as i,o as r,j as a,a2 as o,a as s,G as n,k as l}from"./chunks/framework.DDIT__tB.js";const c={class:"tip custom-block"},m=JSON.parse('{"title":"📊 Model: (AccessControl-DistanceTracker-violation)","description":"","frontmatter":{},"headers":[],"relativePath":"examples/models/dfd/AC-DistanceTracker-violation.md","filePath":"examples/models/dfd/AC-DistanceTracker-violation.md"}'),d={name:"examples/models/dfd/AC-DistanceTracker-violation.md"},f=Object.assign(d,{setup(h){return(p,e)=>(r(),i("div",null,[e[2]||(e[2]=a("h1",{id:"📊-model-accesscontrol-distancetracker-violation",tabindex:"-1"},[s("📊 Model: (AccessControl-DistanceTracker-violation) "),a("a",{class:"header-anchor",href:"#📊-model-accesscontrol-distancetracker-violation","aria-label":'Permalink to "📊 Model: (AccessControl-DistanceTracker-violation)"'},"​")],-1)),a("div",c,[e[0]||(e[0]=a("p",{class:"custom-block-title"},"Available Online",-1)),e[1]||(e[1]=a("p",null,"This model is available to view using the online editor!",-1)),n(l(t),{text:"Open In Online Editor",href:"https://editor.dataflowanalysis.org/?file=https://raw.githubusercontent.com/DataFlowAnalysis/DataFlowAnalysis/refs/heads/main/bundles/org.dataflowanalysis.examplemodels/scenarios/dfd/AC-DistanceTracker-violation/DistanceTracker-violation.json"})]),e[3]||(e[3]=o('<h2 id="🔗-link-to-original-paper-article" tabindex="-1">🔗 Link to Original Paper/Article <a class="header-anchor" href="#🔗-link-to-original-paper-article" aria-label="Permalink to &quot;🔗 Link to Original Paper/Article&quot;">​</a></h2><p><a href="https://ieeexplore.ieee.org/document/8703910" target="_blank" rel="noreferrer">View Source</a><a href="https://github.com/DataFlowAnalysis/DataFlowAnalysis/tree/main/bundles/org.dataflowanalysis.examplemodels/scenarios/dfd/AC-DistanceTracker-violation" target="_blank" rel="noreferrer">Open Example Model in Example Models Bundle</a></p><h2 id="📝-short-description" tabindex="-1">📝 Short Description <a class="header-anchor" href="#📝-short-description" aria-label="Permalink to &quot;📝 Short Description&quot;">​</a></h2><p>The case is about a user that wants to track running statistics by an external service.</p><h2 id="🔤-abbreviations" tabindex="-1">🔤 Abbreviations <a class="header-anchor" href="#🔤-abbreviations" aria-label="Permalink to &quot;🔤 Abbreviations&quot;">​</a></h2><p>None.</p><h2 id="📖-extensive-description" tabindex="-1">📖 Extensive Description <a class="header-anchor" href="#📖-extensive-description" aria-label="Permalink to &quot;📖 Extensive Description&quot;">​</a></h2><p>The <strong>User</strong> sends his/her <em>location</em> to a <em>Distance Tracker</em> service that stores locations in the <strong>Location Store</strong> and derives the run distance. This happens with the <em>consent</em> of the <strong>User</strong>. Afterwards, this service transmits the <em>distance</em> to a <strong>Tracking Service</strong>.</p><h2 id="🏷️-label-description" tabindex="-1">🏷️ Label Description <a class="header-anchor" href="#🏷️-label-description" aria-label="Permalink to &quot;🏷️ Label Description&quot;">​</a></h2><h3 id="🗂️-data-labels" tabindex="-1">🗂️ Data Labels: <a class="header-anchor" href="#🗂️-data-labels" aria-label="Permalink to &quot;🗂️ Data Labels:&quot;">​</a></h3><ul><li><strong>AccessRights</strong>: These are classified as either <code>User</code>, <code>TrackingService</code>, and <code>DistanceTracker</code>, depending on which area the data flow is allowed to flow through.</li></ul><h3 id="🏷️-node-labels" tabindex="-1">🏷️ Node Labels: <a class="header-anchor" href="#🏷️-node-labels" aria-label="Permalink to &quot;🏷️ Node Labels:&quot;">​</a></h3><ul><li><strong>Roles</strong>: These are the same as the data labels. <code>User</code>, <code>TrackingService</code> and <code>DistanceTracker</code> are the three parts of the model. Each node is part of exactly one of these.</li></ul><h2 id="⚠️-constraint" tabindex="-1">⚠️ Constraint <a class="header-anchor" href="#⚠️-constraint" aria-label="Permalink to &quot;⚠️ Constraint&quot;">​</a></h2><h3 id="distancetrackersecurity" tabindex="-1">DistanceTrackerSecurity <a class="header-anchor" href="#distancetrackersecurity" aria-label="Permalink to &quot;DistanceTrackerSecurity&quot;">​</a></h3><p>This constraint ensures that no data flow passes a node it does not have the corresponding label (and access right) for.</p><ul><li><code>DistanceTrackerSecurity: !AccessRights.DistanceTracker neverFlows vertex Roles.DistanceTracker</code></li></ul><h2 id="🚨-violations" tabindex="-1">🚨 Violations <a class="header-anchor" href="#🚨-violations" aria-label="Permalink to &quot;🚨 Violations&quot;">​</a></h2><p>The error introduced in the case is that the calculated distance can bypass the declassification process (<strong>confirm_distance</strong>), which implies a higher classification level.</p>',19))]))}});export{m as __pageData,f as default};
